const existingRows = $('GetSeenPosts').all();
const seenUrls = existingRows.map(i => (i.json.url || '').trim().toLowerCase());

return $input.all().map(item => {
  const input = item.json;

  if (!input.link) return null;

  const currentUrl = input.link.trim().toLowerCase();
  const isSeen = seenUrls.includes(currentUrl);

  return { json: { ...input, isSeen } };
}).filter(item => item !== null);

const rawOutput = $json.text || $json.output || $json.content || '';

// Find all {...} blocks in the raw output
const jsonBlockRegex = /\{[\s\S]*?\}/g;
const matches = rawOutput.match(jsonBlockRegex) || [];

const requiredFields = ['score', 'business_type', 'pain_point'];

// Walk backward - the real answer is usually the last valid block,
// since models sometimes echo schema/instructions before the actual output
for (let i = matches.length - 1; i >= 0; i--) {
  try {
    const parsed = JSON.parse(matches[i]);

    const hasAllRequired = requiredFields.every(field =>
      Object.prototype.hasOwnProperty.call(parsed, field)
    );

    if (hasAllRequired) {
      // Basic type sanity check on score
      const scoreNum = Number(parsed.score);
      if (!isNaN(scoreNum) && scoreNum >= 1 && scoreNum <= 10) {
        return {
          json: {
            ...$json,
            score: scoreNum,
            business_type: parsed.business_type || '',
            pain_point: parsed.pain_point || '',
            inferred: parsed.inferred === true,
            niche_fit: parsed.niche_fit || '',
            parse_error: false
          }
        };
      }
    }
  } catch (e) {
    // not valid JSON, try the next block backward
    continue;
  }
}

// Nothing valid found - fallback
return {
  json: {
    ...$json,
    error: true,
    reason: 'parse_failed',
    raw_output: rawOutput,
    score: 0,
    parse_error: true
  }
};

