const requiredFields = ['link', 'message'];
const results = [];

$input.all().forEach((item) => {
  const rawOutput = item.json.text || item.json.output || item.json.content || '';
  const jsonBlockRegex = /\{[\s\S]*?\}/g;
  const matches = rawOutput.match(jsonBlockRegex) || [];

  let found = false;

  for (let i = matches.length - 1; i >= 0; i--) {
    try {
      const parsed = JSON.parse(matches[i]);
      const hasAllRequired = requiredFields.every(f =>
        Object.prototype.hasOwnProperty.call(parsed, f)
      );

      if (hasAllRequired && parsed.message && parsed.message.trim().length > 0 && parsed.link) {
        results.push({
          json: {
            link: parsed.link.trim(),
            niche: $('FilterHighScorePosts').first().json.niche || '',
            message: parsed.message.trim(),
            logged_at: new Date().toISOString(),
            parse_error: false
          }
        });
        found = true;
        break;
      }
    } catch (e) {
      continue;
    }
  }

  if (!found) {
    results.push({
      json: {
        error: true,
        reason: 'parse_failed',
        raw_output: rawOutput,
        message: '',
        parse_error: true
      }
    });
  }
});

return results;
